import { trackCustomization, senderMetrics } from '@andes/common/build/metrics';

const METRIC_COMPONENT = 'List';

/**
 * @param {import('../..').ListItemProps} componentProps
 */
const isSlotted = ({
  title,
  description,
  rightContent,
  children,
  // @ts-expect-error: internal props
  legacyBehavior,
}) => {
  const defaultContent = title || description || rightContent;
  const shouldSendSlotMetric = legacyBehavior ? children && !defaultContent : children;

  return !!shouldSendSlotMetric;
};

const metrics = senderMetrics(trackCustomization);

export const ListItemMetrics = {
  SSR: [metrics?.sendSlots?.(METRIC_COMPONENT, isSlotted)],
};
