import React from 'react';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import { useId } from '@andes/context';
import { useThemeContext } from '@andes/themes';
import { namespace } from '../constants';
import { LIST_DISPLAY_NAME } from '../constants/components';
import { ListProvider } from '../context/ListContext';
import { getAttributesByListType } from '../utils/getAttributesByListType';

/** @typedef {import('../..').ListProps} ListPublicProps */

/**
 * @typedef {Object} ListInternalProps
 * @prop {'checkbox' | 'listbox' | 'radio' | 'standalone'} [listType]
 */

/** @typedef {ListInternalProps & ListPublicProps} ListProps */

/** @type {React.FunctionComponent<React.ComponentProps<typeof import('../../index').List> & ListProps>} */
const List = ({ ref, ...props }) => {
  const {
    children,
    className,
    component: Component = 'ul',
    id,
    listType = 'standalone',
    selectable = true,
    srLabel,
    type = 'default',
    withDividers = false,
    ...other
  } = props;

  const { getThemedComponentClasses, themeHash } = useThemeContext();
  const componentId = useId(id);
  const { list } = getAttributesByListType(listType)();

  const listClassNames = classNames(namespace, className, `${namespace}--${type}`, getThemedComponentClasses?.('list'), {
    [`${namespace}--selectable`]: selectable,
    [`${namespace}-with-dividers`]: withDividers,
  });

  return (
    <ListProvider listType={listType}>
      <Component
        className={listClassNames}
        id={componentId}
        ref={ref}
        {...other}
        {...themeHash}
        {...list}
        aria-label={srLabel}
      >
        {React.Children.map(children, (/** @type {React.ReactElement | undefined} */ child, index) => {
          let childNewId;

          // When role === 'listbox, @react-aria inject its own ids
          if (props.role !== 'listbox') {
            const childId = child?.props?.id;

            if (childId) {
              childNewId = childId;
            } else if (componentId) {
              childNewId = `${componentId}-${index}`;
            }
          }

          return (
            child && React.cloneElement(child, {
              id: childNewId,
            })
          );
        },
        )}
      </Component>
    </ListProvider>
  );
};

List.displayName = LIST_DISPLAY_NAME;

List.propTypes = {
  children: PropTypes.oneOfType([PropTypes.element, PropTypes.arrayOf(PropTypes.element.isRequired)]),
  className: PropTypes.string,
  component: PropTypes.elementType,
  id: PropTypes.string,
  role: PropTypes.string,
  selectable: PropTypes.bool,
  srLabel: PropTypes.string.isRequired,
  type: PropTypes.oneOf(['default', 'dropdown']),
  withDividers: PropTypes.bool,
  listType: PropTypes.oneOf(['checkbox', 'listbox', 'radio', 'standalone']),
};

export default List;
