import classNames from 'classnames';
import { listItemNamespace } from '../constants';
import { MEDIUM } from '../constants/layout';

/**
 * @typedef {import('../../index').ImageContent} ImageType
 * @typedef {import ('react').FunctionComponentElement<unknown>} ThumbnailComponent
 * @typedef {import('./utils').PropsGetListItemClassNames} Props
 */


/** @type {(props: Props) => string} */
const getListBaseItemClassNames = (props) => {
  const {
    className,
    disabled = false,
    hasDescription = false,
    hasLeftContentImage = false,
    interactive = false,
    paddingSize,
    selected = false,
    size = MEDIUM,
    slotted,
  } = props;

  const computedPaddingSize = Number(paddingSize);

  const listItemClassNames = classNames(listItemNamespace, className, `${listItemNamespace}--size-${size}`, {
    [`${listItemNamespace}--selected-padding-0`]: selected && computedPaddingSize === 0,
    [`${listItemNamespace}--padding-${computedPaddingSize}`]: computedPaddingSize || computedPaddingSize === 0,
    [`${listItemNamespace}--disabled`]: disabled,
    [`${listItemNamespace}--selected`]: selected,
    [`${listItemNamespace}-with-image`]: hasLeftContentImage,
    [`${listItemNamespace}-with-secondary`]: hasDescription && size !== 'small',
    [`${listItemNamespace}--selectable`]: interactive,
    [`${listItemNamespace}--slotted`]: slotted,
  });

  return listItemClassNames;
};

export default getListBaseItemClassNames;
