import { DEFAULT_POSITION_TOP } from '../constants/layout';

/**
 * @typedef {Object} RightContentConfig
 * @prop {'top' | 'centered'} position
 * @prop {import('react').ReactNode} [content]
 * @prop {string} [description]
 */

/**
 * @typedef {Object} RightContent
 * @prop {string} [content]
 * @prop {string} [description]
 */

/**
 * @typedef {Object} Props
 * @prop {import('react').ReactNode | RightContent} [rightContent]
 * @prop {'centered' | 'top'} [rightContentPosition]
 */

/** @type {(value: import('react').ReactNode | RightContent) => value is RightContent} */
const isRightContentType = (value) => /** @type {RightContent} */ (value)?.content !== undefined;


/** @type {(props:Props) => RightContentConfig} */
const computeRightContent = ({
  rightContent: rightContentProp,
  rightContentPosition: rightContentPositionProp,
}) => {
  if (!rightContentProp) return { position: DEFAULT_POSITION_TOP };

  const computedRightContentPosition = {
    position: rightContentPositionProp || DEFAULT_POSITION_TOP,
  };

  if (isRightContentType(rightContentProp)) {
    return {
      ...computedRightContentPosition,
      content: rightContentProp?.content,
      description: rightContentProp?.description ?? undefined,
    };
  }

  return {
    ...computedRightContentPosition,
    content: rightContentProp || null,
    position: rightContentPositionProp || DEFAULT_POSITION_TOP,
  };
};

export default computeRightContent;
