import React from 'react';
import PropTypes from 'prop-types';
import warning from '@andes/common/build/utils/warning';
import { useListContext } from '../context/ListContext';
import ListBaseItem from './ListBaseItem';
import ListItemContent from './ListItemContent';
import ListActionItem from './ListActionItem';
import { hasImage } from '../utils/hasImage';
import { hasSlot } from '../utils/hasSlot';
import { isLegacyLeftContent } from '../utils/isLegacyLeftContent';
import computeRightContent from '../utils/computeRightContent';
import { LIST_ITEM_DISPLAY_NAME } from '../constants/components';
import { AVAILABLE_SIZES, AVAILABLE_PADDING_SIZE, MEDIUM, DEPRECATED_PADDING_SIZE } from '../constants/layout';
import {
  WARNING_LIST_ITEM,
  WARNING_LIST_ITEM_CHILDREN,
  WARNING_HREF,
  WARNING_ON_CLICK,
  WARNING_LIST_ITEM_LEFT_CONTENT,
  WARNING_TARGET,
  WARNING_DISABLED,
  WARNING_CHEVRON,
} from '../constants/warnings';
import { withTracker } from '@andes/with-tracker';
import { ListItemMetrics } from '../metrics';

/** @typedef {React.FunctionComponentElement<unknown>} ThumbnailComponent */
/** @typedef {import('../../index').ImageContent} ImageType */

/**
 * @typedef {Object} ListItemInternalProps
 * @prop {number} [groupIndex]
 * @prop {number} [index]
 * @prop {(
 *  event: React.KeyboardEvent<HTMLLIElement> | React.MouseEvent<HTMLLIElement>,
 *  selectedValue: { value?: string }) => void
 * } [onSelect]
 */

/** @typedef {import('../../index').ListItemProps} ListItemPublicProps */

/** @typedef {ListItemPublicProps & ListItemInternalProps} ListItemProps */

/** @type {React.FunctionComponent<React.ComponentProps<import('@andes/common').PolymorphicExoticComponentRestricted<'li', ListItemProps, 'div' | 'li'>>>} */
const ListItem = ({ ref, ...props }) => {
  const {
    chevron,
    children,
    className,
    description,
    disabled,
    groupIndex,
    href,
    id,
    leftContent,
    maxLines,
    onClick,
    onSelect,
    paddingSize,
    rightContent,
    rightContentPosition = 'top',
    selected = false,
    size = MEDIUM,
    target,
    title,
    value,
    ...other
  } = props;

  const listContext = useListContext();

  const computedRightContent = computeRightContent({ rightContent, rightContentPosition });
  const hasDescription = !!description;
  const hasLeftContentImage = hasImage(leftContent);
  const isSlotted = hasSlot(children, {
    title,
    description,
    rightContent: computedRightContent?.content || computedRightContent?.description,
  }, { legacyBehavior: true });

  const listBaseItemDeprecatedProps = { selected, disabled };
  const listActionItemDeprecatedProps = { selected };
  const listItemContentDeprecatedProps = { chevron: !!chevron, value: value?.toString() };

  warning(!!listContext?.listType, WARNING_LIST_ITEM);
  if (listContext?.listType === 'standalone') {
    // @deprecate [disabled] - Warning from: 9.0.0
    warning(typeof disabled === 'undefined', WARNING_DISABLED);
    // @deprecate [onClick] - Warning from: 9.0.0
    warning(typeof onClick === 'undefined', WARNING_ON_CLICK);
  }

  // @deprecate Warning from: 9.0.0
  warning(!(children && (title || description || rightContent)), WARNING_LIST_ITEM_CHILDREN);

  // @deprecate [chevron] - Warning from: 9.0.0
  warning(typeof chevron === 'undefined', WARNING_CHEVRON);

  // @deprecate [leftContent] - Warning from: 9.0.0
  const legacyLeftContent = isLegacyLeftContent(leftContent);
  warning(!legacyLeftContent, WARNING_LIST_ITEM_LEFT_CONTENT);

  // @deprecate [href] - Warning from: 9.0.0
  warning(typeof href === 'undefined', WARNING_HREF);

  // @deprecate [target] - Warning from: 9.0.0
  warning(typeof target === 'undefined', WARNING_TARGET);

  if (href || onClick) {
    return (
      <ListActionItem
        className={className}
        ref={ref}
        id={id}
        legacyBehavior
        maxLines={maxLines}
        paddingSize={paddingSize}
        size={size}
        chevron={!!chevron}
        href={href}
        target={target}
        disabled={disabled}
        onClick={/** @type {import('../..').ListActionItemProps['onClick']} */ (onClick)}
        title={title}
        description={description}
        leftContent={leftContent}
        rightContent={computedRightContent?.content}
        rightContentPosition={computedRightContent?.position}
        {...listActionItemDeprecatedProps}
        {...other}
      >
        {children}
      </ListActionItem>
    );
  }

  return (
    <ListBaseItem
      className={className}
      id={id}
      ref={ref}
      hasDescription={hasDescription}
      hasLeftContentImage={hasLeftContentImage}
      paddingSize={paddingSize}
      size={size}
      slotted={isSlotted}
      {...listBaseItemDeprecatedProps}
      {...other}
    >
      <ListItemContent
        title={title}
        description={description}
        leftContent={leftContent}
        rightContent={computedRightContent?.content}
        rightContentPosition={computedRightContent?.position}
        maxLines={maxLines}
        size={size}
        baseList
        legacyBehavior
        id={id}
        {...listItemContentDeprecatedProps}
      >
        {children}
      </ListItemContent>
    </ListBaseItem>
  );
};

ListItem.displayName = LIST_ITEM_DISPLAY_NAME;

ListItem.propTypes = {
  addPrimaryLabel: PropTypes.bool,
  baseList: PropTypes.bool,
  chevron: PropTypes.bool,
  children: PropTypes.node,
  className: PropTypes.string,
  component: PropTypes.oneOf(['li', 'div']),
  description: PropTypes.node,
  disabled: PropTypes.bool,
  groupIndex: PropTypes.number,
  href: PropTypes.string,
  id: PropTypes.string,
  leftContent: PropTypes.node,
  maxLines: PropTypes.number,
  onClick: PropTypes.func,
  onSelect: PropTypes.func,
  paddingSize: PropTypes.oneOf([...AVAILABLE_PADDING_SIZE, ...DEPRECATED_PADDING_SIZE]),
  rightContent: PropTypes.oneOfType([
    PropTypes.node,
    PropTypes.shape({
      content: PropTypes.string,
      description: PropTypes.string,
    }),
  ]),
  rightContentPosition: PropTypes.oneOf(['top', 'centered']),
  role: PropTypes.string,
  selected: PropTypes.bool,
  size: PropTypes.oneOf(AVAILABLE_SIZES),
  target: PropTypes.oneOf(['_self', '_blank', '_parent', '_top']),
  title: PropTypes.node,
  value: PropTypes.string,
};

export default withTracker(ListItem, ListItemMetrics);
