import React, { Children, cloneElement, useMemo } from 'react';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import { mergeProps } from '@react-aria/utils';

import groupNodeGenerator from '../generators/groupNodeGenerator';

import { listGroupNamespace } from '../constants';
import { LIST_GROUP_DISPLAY_NAME } from '../constants/components';
import { AVAILABLE_PADDING_SIZE, AVAILABLE_SIZES, MEDIUM } from '../constants/layout';

import { useListContext } from '../context/ListContext';
import { DEPRECATED_PADDING_SIZES_WARNINGS, WARNING_LIST_GROUP } from '../constants/warnings';
import warning from '@andes/common/build/utils/warning';
import includes from '@andes/common/build/utils/includes';
import { getAttributesByListType } from '../utils/getAttributesByListType';

/**
 * @typedef {Object} ListGroupInternalProps
 * @prop {{role: string}} [groupProps]
 * @prop {{id: string, 'aria-hidden'?: boolean }} [headingProps]
 * @prop {{role: string}} [itemProps]
 */

/** @typedef {import('../../index').ListGroupProps} ListGroupPublicProps */

/** @typedef {ListGroupInternalProps & ListGroupPublicProps} ListGroupProps */

/**
 * @type {React.FunctionComponent<ListGroupProps>
 * & { getCollectionNode: (props: ListGroupProps) => Generator} }
 */
const ListGroup = (props) => {
  const {
    children,
    className,
    component: Component = 'ul',
    groupProps,
    headingProps,
    id,
    itemProps,
    label,
    paddingSize,
    size = MEDIUM,
    withDividers = false,
    ...other
  } = props;
  const listContext = useListContext();

  // @deprecate [paddingSize as string] - Warning from: 9.0.0
  if (typeof paddingSize === 'string') {
    warning(
      !includes(Object.keys(DEPRECATED_PADDING_SIZES_WARNINGS), paddingSize),
      DEPRECATED_PADDING_SIZES_WARNINGS[paddingSize],
    );
  }

  const listGroupClassNames = classNames(
    listGroupNamespace,
    className,
    `${listGroupNamespace}--size-${size}`,
    {
      [`${listGroupNamespace}--padding-${paddingSize}`]: paddingSize,
      [`${listGroupNamespace}--with-dividers`]: withDividers,
    },
  );

  const { group, header, sublist } = useMemo(() => (
    getAttributesByListType()()
  ), []);

  warning(!!listContext?.listType, WARNING_LIST_GROUP);

  return (
    <li
      className={listGroupClassNames}
      {...mergeProps(itemProps, other)}
      {...group}
    >
      <span
        className={`${listGroupNamespace}--header`}
        id={id}
        {...headingProps}
        {...header}
      >
        {label}
      </span>
      <Component
        className={`${listGroupNamespace}--sublist`}
        aria-labelledby={id}
        {...groupProps}
        {...sublist}
      >
        {Children.map(children, (child, index) => {
          let childNewId;
          // @ts-expect-error: Themes integration. Check typing.
          const childId = child.props?.id;

          if (childId) {
            childNewId = childId;
          } else if (id) {
            childNewId = `${id}-${index}`;
          }

          // @ts-expect-error: Themes integration. Check typing.
          return cloneElement(child, { id: childNewId });
        })}
      </Component>
    </li>
  );
};

ListGroup.getCollectionNode = groupNodeGenerator;

ListGroup.displayName = LIST_GROUP_DISPLAY_NAME;

ListGroup.propTypes = {
  children: PropTypes.oneOfType([PropTypes.element, PropTypes.arrayOf(PropTypes.element.isRequired)]).isRequired,
  className: PropTypes.string,
  component: PropTypes.oneOf(['ul', 'ol']),
  groupProps: PropTypes.shape({ role: PropTypes.string.isRequired }),
  // aria-hidden could be null according to how prop-types handles optional params,
  // null is not assignable to native aria-hidden attribute
  headingProps: PropTypes.shape({ id: PropTypes.string.isRequired, 'aria-hidden': PropTypes.bool }),
  id: PropTypes.string,
  itemProps: PropTypes.shape({ role: PropTypes.string.isRequired }),
  label: PropTypes.string.isRequired,
  paddingSize: PropTypes.oneOf(AVAILABLE_PADDING_SIZE),
  size: PropTypes.oneOf(AVAILABLE_SIZES),
  withDividers: PropTypes.bool,
};

export default ListGroup;
